<?php require_once __DIR__ . '/app/auth.php'; require_login(); csrf_check(); $pdo=db();
if($_SERVER['REQUEST_METHOD']==='POST'){$customer=(int)$_POST['customer_id'];$st=$pdo->prepare('SELECT c.*,p.price FROM customers c LEFT JOIN packages p ON p.id=c.package_id WHERE c.id=?');$st->execute([$customer]);$c=$st->fetch();if($c){$pdo->prepare('INSERT INTO payments(payment_code,customer_id,invoice_month,amount,paid_at,method,received_by,notes) VALUES(?,?,?,?,?,?,?,?)')->execute([payment_code(),$customer,trim($_POST['invoice_month']),(int)$_POST['amount'],trim($_POST['paid_at']),trim($_POST['method']),$_SESSION['user']['name'],trim($_POST['notes'])]);}redirect('payments.php');}
require_once __DIR__ . '/app/layout.php'; $selected=(int)($_GET['customer_id']??0); $customers=$pdo->query('SELECT c.*,p.price,p.name package_name FROM customers c LEFT JOIN packages p ON p.id=c.package_id ORDER BY c.name ASC')->fetchAll(); $rows=$pdo->query('SELECT pay.*,c.name customer_name,c.customer_code FROM payments pay JOIN customers c ON c.id=pay.customer_id ORDER BY pay.paid_at DESC,pay.id DESC LIMIT 80')->fetchAll(); render_header('Pembayaran'); ?>
<div class="grid-2"><form class="card form-card" method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><div class="panel-title"><h2>Input Pembayaran</h2></div><div class="form-grid"><div class="field"><label>Pelanggan</label><select name="customer_id" id="customerSelect" required onchange="setAmount()"><option value="">Pilih pelanggan</option><?php foreach($customers as $c):?><option data-price="<?=e($c['price']??0)?>" value="<?=$c['id']?>" <?=$selected===$c['id']?'selected':''?>><?=e($c['customer_code'].' - '.$c['name'].' / '.$c['package_name'])?></option><?php endforeach;?></select></div><div class="field"><label>Bulan Tagihan</label><input name="invoice_month" type="month" value="<?=e(current_month())?>" required></div><div class="field"><label>Nominal</label><input id="amount" name="amount" type="number" required></div><div class="field"><label>Tanggal Bayar</label><input name="paid_at" type="date" value="<?=date('Y-m-d')?>" required></div><div class="field"><label>Metode</label><select name="method"><option>Cash</option><option>Transfer</option><option>QRIS</option><option>Lainnya</option></select></div><div class="field"><label>Catatan</label><input name="notes" placeholder="Opsional"></div></div><button class="btn primary mt-5">Simpan Pembayaran</button></form><div class="card"><div class="panel-title"><h2>Riwayat Pembayaran</h2></div><div class="table-wrap"><table><thead><tr><th>Kode</th><th>Tanggal</th><th>Pelanggan</th><th>Bulan</th><th>Nominal</th><th>Metode</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><b><?=e($r['payment_code'])?></b></td><td><?=e($r['paid_at'])?></td><td><?=e($r['customer_code'].' - '.$r['customer_name'])?></td><td><?=e($r['invoice_month'])?></td><td><b><?=rupiah($r['amount'])?></b></td><td><span class="pill blue"><?=e($r['method'])?></span></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="6">Belum ada pembayaran.</td></tr><?php endif;?></tbody></table></div></div></div><script>function setAmount(){const o=document.querySelector('#customerSelect').selectedOptions[0];if(o&&o.dataset.price)document.querySelector('#amount').value=o.dataset.price}setAmount()</script><?php render_footer(); ?>
